const ERRORS_MESSAGES = {
    required: 'Обязательное поле',
    hasNotNumbers: 'Поле не должно содержать цифры',
    hasNotSpecChars: 'Поле не должно содержать специальных символов',
}

const BASE_RULES = {
    required: v => !!v
        || ERRORS_MESSAGES.required,
    hasNotNumbers: v => !/[0-9]/.test(v)
        || ERRORS_MESSAGES.hasNotNumbers,
    hasNotSpecChars: v => !/[~`!@#$%^&*+=\-\[\]\\';,/{}|":<>?]/.test(v)
        || ERRORS_MESSAGES.hasNotSpecChars,
}

const RULES = {
    onlyText: [
        BASE_RULES.required,
        BASE_RULES.hasNotNumbers,
        BASE_RULES.hasNotSpecChars,
        v => (v && v.length > 6) || 'Имя должен быть больше 6 символов',
    ],
    email: [
        BASE_RULES.required,
        v => /.+@.+\..+/.test(v) || 'Введите валидный email',
    ],
    login: [
        BASE_RULES.required,
        v => (v && v.length > 6) || 'Логин должен быть больше 6 символов',
        v => (v && v.length <= 20) || 'Логин не может быть больше 20 символов',
    ],
    password: [
        BASE_RULES.required,
        v => (v && v.length > 6) || 'Пароль должен быть больше 6 символов',
    ],
    agreement: [
        BASE_RULES.required
    ],
}

export const RULE = Object.freeze({
    EMAIL: 'email',
    LOGIN: 'login',
    PASSWORD: 'password',
    ONLY_TEXT: 'onlyText',
    AGREEMENT: 'agreement',
})

export const getValidateRule = field => [...RULES[field]]