<template>
  <BasePage>
    <BaseSection title="Вход">
      <div id="sign-in-page">
        <div id="sign-in-page-form">
          <FormCard
              :fields="fields"
              :is-loading="isLoading"
              prepend-text="Нет аккаунта?"
              :prepend-link="{ name: 'SignUp' }"
              prepend-link-text="Зарегистрироваться"
              @valid-update="validUpdate"
              @submit="signIn"
          />
        </div>
      </div>
    </BaseSection>
  </BasePage>
</template>

<script>
import BaseSection from "@/components/BaseSection"
import FilmsTable from '@/components/FilmsTable'
import FormCard from "@/components/FormCard"
import {getValidateRule, RULE} from "@/ext"
import {mapActions} from "vuex"
import BasePage from "@/components/BasePage";

export default {
  name: 'SignIn',
  components: {
    FilmsTable,
    BaseSection,
    BasePage,
    FormCard
  },
  data() {
    return {
      isFormValid: false,
      isLoading: false,
      fields: [
        {
          is: 'v-text-field',
          name: 'login',
          label: 'Логин',
          rules: getValidateRule(RULE.LOGIN),
          type: 'text',
        },
        {
          is: 'v-text-field',
          name: 'password',
          label: 'Пароль',
          rules: getValidateRule(RULE.PASSWORD),
          type: 'password',
        },
      ],
    }
  },
  methods: {
    ...mapActions([
        'auth'
    ]),
    validUpdate(val) {
      this.isFormValid = val
    },
    async signIn(userCredentials) {
      this.isLoading = true

      await this.auth(userCredentials)

      this.isLoading = false

      this.$router.push({
        name: 'Home',
      }).catch(() => {})
    },
  },
}
</script>

