import Vue from 'vue'
import VueRouter from 'vue-router'
import Home from '../views/Home.vue'
import Film from '@/views/Film'
import SignIn from '@/views/SignIn'
import Cart from '@/views/Cart'
import Films from '@/views/Films'
import SignUp from "@/views/SignUp";

Vue.use(VueRouter)

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home
  },
  {
    path: '/film/:id',
    name: 'Film',
    component: Film
  },
  {
    path: '/films',
    name: 'Films',
    component: Films
  },
  {
    path: '/sign-in',
    name: 'SignIn',
    component: SignIn
  },
  {
    path: '/sign-up',
    name: 'SignUp',
    component: SignUp
  },
  {
    path: '/cart',
    name: 'Cart',
    component: Cart
  },
  {
    path: '*',
    name: 'NotFound',
    component: Home,
  },
]

const router = new VueRouter({
  routes
})

export default router
