<template>
  <v-app-bar
    app
    dark
    hide-on-scroll
  >
    <router-link :to="{ name: 'Home' }" id="logotype-wrapper">
      <img src="@/assets/logo.png" alt="">
    </router-link>
    <v-spacer/>
    <div id="app-header-inner-actions">
      <template v-if="isCartEmpty">
        <v-icon
          size="20"
          @click="redirectToCart"
        >mdi-cart</v-icon>
      </template>
      <template v-else>
        <v-badge
          color="green"
          offset-x="8"
          offset-y="8"
          dark
          :content="cart.length"
          bottom
          left
        >
          <v-icon
            size="20"
            @click="redirectToCart"
          >mdi-cart</v-icon>
        </v-badge>
      </template>
      <v-divider
        vertical
        class="mx-1"
      />
      <template v-if="isAuthed">
        <div class="base-header-username">{{ user.login }}</div>
        <v-btn
          @click="appLogout"
          text
          depressed
          small
          color="error"
          class="py-0 px-2"
        >
          Выйти
        </v-btn>
      </template>
      <template v-else>
        <v-btn
          @click="redirectToSignIn"
          elevation="2"
          color="primary"
          small
        >
          Войти
        </v-btn>
      </template>
    </div>
  </v-app-bar>
</template>

<script>
import {mapActions, mapGetters} from "vuex";

export default {
  name: "BaseHeader",
  computed: {
    ...mapGetters([
        'cart',
        'isCartEmpty',
        'isAuthed',
        'user',
    ]),
  },
  methods: {
    ...mapActions([
        'logout'
    ]),
    appLogout() {
      this.logout()

      this.$router.push({ name: 'Home' }).catch(() => {})
    },
    redirectToSignIn() {
      this.$router.push({ name: 'SignIn' }).catch(() => {})
    },
    redirectToCart() {
      this.$router.push({ name: 'Cart' }).catch(() => {})
    },
  },
}
</script>

