<template>
  <section
    class="base-section"
    :class="{
      'base-section__dense': dense
    }"
  >
    <div class="base-section-inner" :style="innerStyle">
      <template v-if="title">
        <component
          class="base-section-title"
          v-bind="titleProps"
        >
          {{ title }}
          <v-icon
            v-if="titleLink"
            class="base-section-title-link-chevron"
            large
          >mdi-chevron-right</v-icon>
        </component>
      </template>
      <slot/>
    </div>
  </section>
</template>

<script>
export default {
  name: "BaseSection",
  props: {
    title: String,
    titleLink: Object,
    dense: Boolean,
    innerStyle: Object,
  },
  computed: {
    titleProps() {
      return this.titleLink ? {
        to: this.titleLink,
        is: 'router-link',
        class: ['base-section-title-link'],
      } : {
        is: 'div',
      }
    },
  },
}
</script>

