<template>
  <BasePage>
    <BaseSection title="Регистрация">
      <div id="sign-up-page">
        <div id="sign-up-page-form">
          <FormCard
              :fields="fields"
              :is-loading="isLoading"
              prepend-text="Есть аккаунт?"
              :prepend-link="{ name: 'SignIn' }"
              prepend-link-text="Войти"
              @valid-update="validUpdate"
              @submit="signIn"
          />
        </div>
      </div>
    </BaseSection>
  </BasePage>
</template>

<script>
import BaseSection from "@/components/BaseSection"
import FilmsTable from '@/components/FilmsTable'
import FormCard from "@/components/FormCard"
import {getValidateRule, RULE} from "@/ext"
import {mapActions} from "vuex"
import BasePage from "@/components/BasePage";

export default {
  name: 'SignUp',
  components: {
    FilmsTable,
    BaseSection,
    BasePage,
    FormCard
  },
  data() {
    return {
      isFormValid: false,
      isLoading: false,
      fields: [
        {
          is: 'v-text-field',
          name: 'first_name',
          label: 'Имя *',
          rules: getValidateRule(RULE.ONLY_TEXT),
          type: 'text',
        },
        {
          is: 'v-text-field',
          name: 'email',
          label: 'Электронная почта *',
          rules: getValidateRule(RULE.EMAIL),
          type: 'text',
        },
        {
          is: 'v-text-field',
          name: 'login',
          label: 'Логин *',
          rules: getValidateRule(RULE.LOGIN),
          type: 'text',
        },
        {
          is: 'v-text-field',
          name: 'password',
          label: 'Пароль *',
          rules: getValidateRule(RULE.PASSWORD),
          type: 'password',
        },
        {
          is: 'v-select',
          name: 'sex',
          label: 'Пол',
          rules: [],
          items: [
            'Мужской',
            'Женский'
          ],
        },
        {
          is: 'v-checkbox',
          name: 'agreement',
          label: 'Согласен с правилами сайта *',
          rules: getValidateRule(RULE.AGREEMENT),
          items: [
            'Мужской',
            'Женский'
          ],
          style: {
            marginTop: '-10px',
            marginBottom: '10px',
          },
        },
      ],
    }
  },
  methods: {
    ...mapActions([
      'auth'
    ]),
    validUpdate(val) {
      this.isFormValid = val
    },
    async signIn(userCredentials) {
      this.isLoading = true

      await this.auth(userCredentials)

      this.isLoading = false

      this.$router.push({
        name: 'Home',
      }).catch(() => {})
    },
  },
}
</script>

