<template>
  <v-card
    class="form-card-wrapper"
    rounded
  >
    <!--Импорт полей-->
    <v-text-field v-if="false"/>
    <v-select v-if="false"/>
    <v-checkbox v-if="false"/>
    <v-form
      @submit.prevent="submit"
      ref="form"
      class="form-card"
      v-model="valid"
    >
      <slot name="fields">
        <template v-for="field in fields">
          <component
            v-bind="{
              ...baseFieldSettings,
              ...field,
              value: values[field.name],
              key: field.name,
            }"
            @input="value => updateFieldValue(value, field.name)"
          />
        </template>
      </slot>
      <slot name="button">
        <v-btn
          class="form-card-submit"
          color="primary"
          type="submit"
          block
          :disabled="!valid"
          :loading="isLoading"
        >{{ submitButtonText }}</v-btn>
      </slot>
      <slot name="prepend">
        <div class="form-card-prepend">
          <div class="form-card-prepend-text">
            {{ prependText }}
          </div>
          <router-link
              :to="prependLink"
              class="form-card-prepend-link"
          >
            {{ prependLinkText }}
          </router-link>
        </div>
      </slot>
    </v-form>
  </v-card>
</template>

<script>
export default {
  name: "FormCard",
  data: () => ({
    valid: false,
    values: {},
  }),
  props: {
    isLoading: {
      type: Boolean,
      default: false,
    },
    fields: {
      type: Array,
      default: () => [],
    },
    baseFieldSettings: {
      type: Object,
      default: () => ({
        filled: true,
        outlined: true,
        dense: true,
        required: true,
      }),
    },
    submitButtonText: {
      type: String,
      default: 'Отправить',
    },
    prependText: String,
    prependLink: Object,
    prependLinkText: String,
  },
  watch: {
    valid() {
      this.$emit('valid-update', this.valid)
    },
  },
  methods: {
    submit() {
      this.$refs.form.validate()

      if (!this.valid) return

      const formData = this.values

      this.$emit('submit', formData)
    },
    updateFieldValue(value, fieldName) {
      this.$set(this.values, fieldName, value)
    },
  },
}
</script>

