import Vue from 'vue'
import Vuex from 'vuex'
import { FILMS } from '@/ext'

Vue.use(Vuex)

const localStorageController = {
  USER_KEY: 'user_data',
  deleteUser() {
    localStorage.removeItem(this.USER_KEY)
  },
  setUser(user) {
    localStorage.setItem(
      this.USER_KEY,
      JSON.stringify(user)
    )
  },
  getUser() {
    const stringUser = localStorage.getItem(this.USER_KEY)

    return JSON.parse(stringUser)
  }
}

const getRandomInt = max => Math.floor(Math.random() * max)

const getRandomItem = arr => arr[getRandomInt(arr.length)]

export default new Vuex.Store({
  state: {
    user: localStorageController.getUser(),
    films: FILMS(),
    cart: [],
  },
  mutations: {
    ADD_TO_CART: ({ cart, films }, id) => {
      if (cart.includes(id) || !(id in films)) return

      cart.push(id)
    },
    REMOVE_FROM_CART: ({ cart }, id) => {
      const removingId = cart.indexOf(id)

      if (removingId !== -1) {
        Vue.delete(cart, removingId)
      }
    },
    TOGGLE_CART_ITEM({ cart }, id) {
      if (cart.includes(id)) {
        this.commit('REMOVE_FROM_CART', id)
      } else {
        this.commit('ADD_TO_CART', id)
      }
    },
    PRINT_RAW_FILMS({ films }) {
      console.log(films)
    },
    AUTH(state, { login }) {
      const user = { login }

      localStorageController.setUser(user)
      state.user = user
    },
    LOGOUT(state) {
      state.user = null
      localStorageController.deleteUser()
    },
  },
  actions: {
    addToCart: ({ commit }, id) => {
      commit('ADD_TO_CART', id)
    },
    removeFromCart: ({ commit }, id) => {
      commit('REMOVE_FROM_CART', id)
    },
    toggleCartItem: ({ commit }, id) => {
      commit('TOGGLE_CART_ITEM', id)
    },
    rawFilms: ({ commit }) => {
      commit('PRINT_RAW_FILMS')
    },
    auth: async ({ commit }, userCredentials) => {
      return new Promise(resolve => {
        setTimeout(() => {
          commit('AUTH', userCredentials)
          resolve(true)
        }, 1500)
      })
    },
    logout: ({ commit }) => {
      commit('LOGOUT')
    },
  },
  getters: {
    cart: state => state.cart,
    user: state => state.user,
    isAuthed: state => !!state.user,
    films: state => Object.values(state.films),
    filmsInCart: state => state.cart.map(filmId => state.films[filmId]),
    getFilm: state => id => state.films[id],
    getRandomFilm: state => () => getRandomItem(Object.values(state.films)),
    isCartEmpty: state => state.cart.length === 0,
    isFilmAdded: ({ cart }) => id => cart.includes(id),
    isFilmExist: state => id => id in state.films,
    cartPrice: state => state.cart.reduce((prev, cur) => prev + state.films[cur].price, 0),
    bestFilms: state => size => {
      const sort = (a, b) => {
        if (a.rating > b.rating) return -1
        if (a.rating < b.rating) return 1
        return 0
      }

      return Object.values(state.films).sort(sort).slice(0, size)
    },
  },
})
