<template>
  <BaseSection :title="title" :dense="dense">
    <div class="films-carousel">
      <VueSlickCarousel
        v-bind="settings"
        @swipe="setIsSwiping(true)"
        @mouseup.native="setIsSwiping(false)"
        @touchend.native="setIsSwiping(false)"
        :class="{ '--swiping' : isSwiping }"
      >
        <div
          class="films-carousel-item"
          v-for="film in compilation"
          :key="film.id"
          @click.capture=""
        >
          <FilmCard
            v-bind="film"
            :disabledRedirect="isSwiping"
          />
        </div>
      </VueSlickCarousel>
    </div>
  </BaseSection>
</template>

<script>
import BaseSection from "@/components/BaseSection";
import VueSlickCarousel from 'vue-slick-carousel'
import 'vue-slick-carousel/dist/vue-slick-carousel.css'
import 'vue-slick-carousel/dist/vue-slick-carousel-theme.css'
import FilmCard from "@/components/FilmCard";
import {mapGetters} from "vuex";

export default {
  name: "FilmsCompilation",
  props: {
    title: String,
    compilation: Array,
    dense: Boolean,
  },
  data: () => ({
    debounce: null,
    isSwiping: false,
    settings: {
      arrows: false,
      dots: true,
      infinite: false,
      autoplay: false,
      slidesToShow: 6,
      slidesToScroll: 1,
      swipeToSlide: true,
      responsive: [
        {
          breakpoint: 1100,
          settings: {
            slidesToShow: 5,
          },
        },
        {
          breakpoint: 900,
          settings: {
            slidesToShow: 4,
          },
        },
        {
          breakpoint: 700,
          settings: {
            slidesToShow: 3,
          },
        },
        {
          breakpoint: 500,
          settings: {
            slidesToShow: 2,
          },
        }
      ],
    },
  }),
  computed: {
    ...mapGetters([
        'films'
    ]),
  },
  components: {
    BaseSection,
    FilmCard,
    VueSlickCarousel
  },
  methods: {
    setIsSwiping(val) {
      this.isSwiping = val
    },
  },
}
</script>

