<template>
  <BasePage
    :key="film.id"
    :background-image="film.background"
  >
    <div class="film-page" :key="film.id">
      <BaseSection :title="film.title">
        <div class="film-page-wrapper">
          <div
              class="film-page-background"
              :style="{
            background: `url('${ film.background }') 50% 50%`,
            backgroundSize: 'cover'
          }"
          />
          <div class="film-page-section">
            <div class="film-page-section-image">
              <div
                  class="film-page-section-image-inner"
                  :style="{
                background: `url('${film.photo}') 50% 50%`,
                backgroundSize: 'cover',
              }"
              />
            </div>
            <div class="film-page-section-info">
              <div class="film-page-section-info-inner">
                <div class="film-page-section-info-inner-title">О фильме</div>
                <div
                    v-for="item in infoItems"
                    class="film-page-section-info-inner-item"
                >
                  <div class="film-page-section-info-inner-item-title">{{ item.title }}:</div>
                  <div class="film-page-section-info-inner-item-content">{{ item.content }}</div>
                </div>
                <div class="film-page-section-info-inner-title">Покупка</div>
                <v-btn
                    v-bind="addToCartBtnProps"
                    @click="toggleCartItem(film.id)"
                >
                  <template v-if="curFilmAdded">
                    Убрать из корзины
                  </template>
                  <template v-else>
                    В корзину за {{ film.price }}₽
                  </template>
                </v-btn>
              </div>
              <div class="film-page-section-info-rating">{{ film.rating }}</div>
            </div>
          </div>
          <div class="film-page-footer">
            <div class="film-page-footer-item film-page-footer-item-rating">
              <div class="film-page-footer-item-title">Рейтинг</div>
              <div class="film-page-footer-item-rating-content">{{ film.rating }}</div>
            </div>
            <div
                v-for="item in footerItems"
                class="film-page-footer-item"
            >
              <div class="film-page-footer-item-title">{{ item.title }}</div>
              <div class="film-page-footer-item-content">{{ item.content }}</div>
            </div>
          </div>
        </div>
      </BaseSection>
      <FilmsCompilation
          title="Топ-5"
          :compilation="bestFilms(5)"
          dense
      />
    </div>
  </BasePage>
</template>

<script>
import FilmsTable from '@/components/FilmsTable'
import BaseSection from "@/components/BaseSection"
import { mapActions, mapGetters } from "vuex";
import FilmsSimilar from "@/components/FilmsCompilation";
import FilmsCompilation from "@/components/FilmsCompilation";
import BasePage from "@/components/BasePage";

export default {
  name: 'Film',
  computed: {
    ...mapGetters([
        'isFilmAdded',
        'isFilmExist',
        'getFilm',
        'cart',
        'bestFilms'
    ]),
    curFilmAdded() {
      return this.isFilmAdded(this.film.id)
    },
    film() {
      const filmId = this.$route.params.id
      const film = this.getFilm(filmId)

      return film || {}
    },
    addToCartBtnProps() {
      return this.curFilmAdded
        ? {}
        : { color: 'success' }
    },
    footerItems() {
      return [
        {
          title: 'Обзор',
          content: this.film.description,
        },
      ]
    },
    infoItems() {
      return [
        {
          title: 'Название',
          content: this.film.title,
        },
        {
          title: 'Слоган',
          content: this.film.slogan,
        },
        {
          title: 'Год',
          content: this.film.year,
        },
        {
          title: 'Жанр',
          content: this.film.genre,
        },
      ]
    },
  },
  methods: {
    ...mapActions([
        'addToCart',
        'removeFromCart',
        'toggleCartItem'
    ]),
    scrollToTop() {
      window.scrollTo({top: 0, behavior: 'smooth'})
    },
  },
  watch: {
    film() {
      this.scrollToTop()
    },
  },
  components: {
    FilmsCompilation,
    FilmsTable,
    BaseSection,
    BasePage
  },
  created() {
    const { id } = this.$route.params

    const isFilmExist = this.isFilmExist(id)

    if (!isFilmExist) {
      this.$router.push({ name: 'Home' })
    }

    this.scrollToTop()
  },
}
</script>

